:root {
  --bg: #f4f7fb;
  --surface: #ffffff;
  --ink: #1a2230;
  --muted: #54607a;
  --line: #d4dbe6;
  --brand: #0f4c81;
  --brand-strong: #0a3a64;
  --accent: #1f7a5a;
  --focus: #c25a00;
  --radius: 12px;
}

* {
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
}

body {
  margin: 0;
  font-family: system-ui, -apple-system, "Segoe UI", Roboto, sans-serif;
  color: var(--ink);
  background: var(--bg);
  line-height: 1.55;
}

a {
  color: var(--brand);
}

img {
  max-width: 100%;
}

.wrap {
  max-width: 1100px;
  margin: 0 auto;
  padding: 0 20px;
}

/* Skip link */
.skip-link {
  position: absolute;
  left: 12px;
  top: -60px;
  background: #fff;
  color: var(--ink);
  padding: 10px 16px;
  border: 2px solid var(--focus);
  border-radius: 8px;
  z-index: 50;
  transition: top 0.15s ease;
}
.skip-link:focus {
  top: 12px;
}

/* Focus visibility everywhere */
a:focus-visible,
button:focus-visible,
input:focus-visible,
select:focus-visible,
[tabindex]:focus-visible {
  outline: 3px solid var(--focus);
  outline-offset: 2px;
  border-radius: 4px;
}

/* Header */
.site-header {
  position: sticky;
  top: 0;
  z-index: 10;
  background: rgba(255, 255, 255, 0.92);
  backdrop-filter: saturate(140%) blur(8px);
  border-bottom: 1px solid var(--line);
}
.bar {
  max-width: 1100px;
  margin: 0 auto;
  padding: 10px 20px;
  display: flex;
  align-items: center;
  gap: 16px;
}
.brand {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  text-decoration: none;
  color: var(--ink);
  font-weight: 700;
  font-size: 1.05rem;
}
.brand svg {
  width: 26px;
  height: 26px;
  color: var(--brand);
}
.brand small {
  display: block;
  font-weight: 400;
  font-size: 0.75rem;
  color: var(--muted);
}
.site-header nav {
  display: flex;
  gap: 14px;
  margin-left: auto;
}
.site-header nav a {
  text-decoration: none;
  color: var(--ink);
  font-size: 0.95rem;
  padding: 6px 2px;
}
.site-header nav a:hover {
  color: var(--brand);
}
.cta {
  text-decoration: none;
  background: var(--brand);
  color: #fff;
  padding: 9px 14px;
  border-radius: 8px;
  font-weight: 600;
  font-size: 0.95rem;
}
.cta:hover {
  background: var(--brand-strong);
}

/* Hero */
.hero {
  background:
    radial-gradient(1200px 400px at 80% -10%, rgba(31, 122, 90, 0.10), transparent 60%),
    linear-gradient(180deg, #eef4fb, var(--bg));
  border-bottom: 1px solid var(--line);
}
.hero-inner {
  max-width: 820px;
  margin: 0 auto;
  padding: 56px 20px 48px;
}
.eyebrow {
  text-transform: uppercase;
  letter-spacing: 0.08em;
  font-size: 0.78rem;
  font-weight: 700;
  color: var(--accent);
  margin: 0 0 8px;
}
.hero h1 {
  font-size: clamp(1.9rem, 4vw, 2.8rem);
  line-height: 1.12;
  margin: 0 0 14px;
  letter-spacing: -0.01em;
}
.lede {
  font-size: 1.1rem;
  color: var(--muted);
  max-width: 60ch;
  margin: 0 0 22px;
}
.hero-actions {
  display: flex;
  flex-wrap: wrap;
  gap: 12px;
  margin-bottom: 26px;
}
.btn {
  display: inline-block;
  border: 2px solid transparent;
  text-decoration: none;
  font-weight: 600;
  font-size: 1rem;
  padding: 11px 18px;
  border-radius: 10px;
  cursor: pointer;
}
.btn-primary {
  background: var(--brand);
  color: #fff;
}
.btn-primary:hover {
  background: var(--brand-strong);
}
.btn-ghost {
  background: transparent;
  color: var(--brand);
  border-color: var(--brand);
}
.btn-ghost:hover {
  background: rgba(15, 76, 129, 0.08);
}
.btn-block {
  width: 100%;
}
.hero-notes {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-wrap: wrap;
  gap: 10px 22px;
  color: var(--muted);
  font-size: 0.95rem;
}
.hero-notes li {
  display: inline-flex;
  align-items: center;
  gap: 8px;
}
.hero-notes svg {
  width: 18px;
  height: 18px;
  color: var(--accent);
}

/* Sections */
.section {
  padding: 52px 0;
}
.section-alt {
  background: var(--surface);
  border-block: 1px solid var(--line);
}
.section h2 {
  font-size: clamp(1.5rem, 3vw, 2rem);
  margin: 0 0 8px;
  letter-spacing: -0.01em;
}
.section-lead {
  color: var(--muted);
  max-width: 65ch;
  margin: 0 0 24px;
}

/* Cards */
.cards {
  list-style: none;
  margin: 0;
  padding: 0;
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
  gap: 16px;
}
.card {
  background: var(--surface);
  border: 1px solid var(--line);
  border-radius: var(--radius);
  padding: 18px;
}
.card-icon {
  display: inline-flex;
  width: 38px;
  height: 38px;
  align-items: center;
  justify-content: center;
  background: #e8f1ec;
  color: var(--accent);
  border-radius: 10px;
  margin-bottom: 10px;
}
.card-icon svg {
  width: 22px;
  height: 22px;
}
.card h3 {
  margin: 0 0 6px;
  font-size: 1.05rem;
}
.card p {
  margin: 0;
  color: var(--muted);
  font-size: 0.95rem;
}

/* Two col */
.grid-2 {
  display: grid;
  grid-template-columns: 1.2fr 1fr;
  gap: 32px;
  align-items: start;
}

/* Availability steps */
.steps {
  margin: 0;
  padding-left: 20px;
}
.steps li {
  margin-bottom: 12px;
}
.steps strong {
  display: block;
  margin-bottom: 2px;
}

.note {
  background: #eef4fb;
  border: 1px solid var(--line);
  border-left: 4px solid var(--brand);
  border-radius: 10px;
  padding: 16px 18px;
}
.note h3 {
  margin: 0 0 8px;
  font-size: 1.02rem;
}
.note ul {
  margin: 0;
  padding-left: 18px;
}
.note li {
  margin-bottom: 6px;
}

/* Booking form */
.book-form {
  display: grid;
  gap: 16px;
  max-width: 640px;
}
.field {
  display: grid;
  gap: 5px;
}
.field label {
  font-weight: 600;
  font-size: 0.95rem;
}
.field input,
.field select {
  font: inherit;
  color: var(--ink);
  background: #fff;
  border: 1px solid var(--line);
  border-bottom-width: 2px;
  border-radius: 8px;
  padding: 10px 12px;
  width: 100%;
}
.field input:focus,
.field select:focus {
  outline: none;
  border-color: var(--brand);
  box-shadow: 0 0 0 3px rgba(15, 76, 129, 0.18);
}
.help {
  color: var(--muted);
  font-size: 0.85rem;
}
.when {
  border: 1px solid var(--line);
  border-radius: 10px;
  padding: 14px 16px;
  margin: 0;
}
.when legend {
  font-weight: 600;
  padding: 0 4px;
}
.checks {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
  gap: 8px;
  margin-top: 8px;
}
.check {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  font-size: 0.95rem;
  padding: 8px 10px;
  border: 1px solid var(--line);
  border-radius: 8px;
  cursor: pointer;
  background: #fff;
}
.check:hover {
  border-color: var(--brand);
}
.check.remember {
  display: flex;
  background: #f6f9fc;
}
.status {
  margin: 0;
  font-weight: 600;
  color: var(--accent);
  min-height: 1.2em;
}
.fineprint {
  margin: 0;
  font-size: 0.82rem;
  color: var(--muted);
}

/* Contact */
.contact-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: grid;
  gap: 14px;
}
.contact-list li {
  display: flex;
  gap: 12px;
  align-items: flex-start;
}
.contact-list svg {
  width: 22px;
  height: 22px;
  color: var(--brand);
  margin-top: 2px;
  flex-shrink: 0;
}
.contact-list strong {
  display: block;
}
.contact-list a {
  display: block;
  text-decoration: none;
}
.contact-list small {
  display: block;
  color: var(--muted);
  font-size: 0.85rem;
}

/* Footer */
.site-footer {
  background: #0f1b2d;
  color: #cdd8ea;
  padding: 36px 0;
  margin-top: 24px;
}
.footer-grid {
  display: grid;
  grid-template-columns: 1fr 1fr 1.2fr;
  gap: 20px;
  align-items: start;
}
.site-footer a {
  color: #fff;
  text-decoration: none;
  display: block;
  padding: 3px 0;
}
.site-footer a:hover {
  text-decoration: underline;
}
.brand-sm {
  font-weight: 700;
  margin: 0 0 4px;
  color: #fff;
}
.muted {
  color: #9fb0c9;
  font-size: 0.9rem;
}

/* Responsive */
@media (max-width: 820px) {
  .site-header nav {
    display: none;
  }
  .grid-2 {
    grid-template-columns: 1fr;
  }
  .footer-grid {
    grid-template-columns: 1fr;
  }
}
@media (max-width: 480px) {
  .hero-inner {
    padding: 36px 18px;
  }
  .section {
    padding: 36px 0;
  }
  .bar {
    flex-wrap: wrap;
  }
  .cta {
    margin-left: auto;
  }
}

@media (prefers-reduced-motion: reduce) {
  * {
    transition: none !important;
    scroll-behavior: auto !important;
  }
}

